import React, { useState, useEffect, useContext } from "react";
import { AuthContext } from "../AuthContext";
import "./ClienteDashboard.css"; // estilos externos

function ClienteDashboard() {
  const { user } = useContext(AuthContext);
  const [productos, setProductos] = useState([]);
  const [carrito, setCarrito] = useState([]);
  const [mostrarCarrito, setMostrarCarrito] = useState(false);

  useEffect(() => {
    // Simulación: en producción haz fetch a tu backend
    setProductos([
      { id: 1, nombre: "Auriculares inalámbricos", precio: 129.99, stock: 10 },
      { id: 2, nombre: "Batería eléctrica", precio: 699.99, stock: 5 },
      { id: 3, nombre: "Bicicleta de montaña", precio: 349.99, stock: 8 },
    ]);
  }, []);

  const agregarAlCarrito = (producto) => {
    const existe = carrito.find((p) => p.id === producto.id);
    if (existe) {
      setCarrito(
        carrito.map((p) =>
          p.id === producto.id ? { ...p, cantidad: p.cantidad + 1 } : p
        )
      );
    } else {
      setCarrito([...carrito, { ...producto, cantidad: 1 }]);
    }
  };

  const actualizarCantidad = (id, cantidad) => {
    setCarrito(
      carrito.map((p) =>
        p.id === id ? { ...p, cantidad: Math.max(1, cantidad) } : p
      )
    );
  };

  const eliminarProducto = (id) => {
    setCarrito(carrito.filter((p) => p.id !== id));
  };

  const total = carrito.reduce((acc, p) => acc + p.precio * p.cantidad, 0);

  return (
    <div className="cliente-dashboard">
      {/* Panel lateral */}
      <aside className="sidebar">
        <h3>Menú Cliente</h3>
        <ul>
          <li><button>Configurar cuenta</button></li>
          <li><button>Histórico de pedidos</button></li>
          <li><button>Facturas</button></li>
          <li><button>Calificar pedido</button></li>
          <li><button>Pedido en curso</button></li>
          <li><button>Editar pedido</button></li>
        </ul>
      </aside>

      {/* Área principal */}
      <main className="main-content">
        {/* Barra superior */}
        <header className="topbar">
          <h2>Bienvenido, {user?.nombre || "Cliente"}</h2>
          <button className="cart-btn" onClick={() => setMostrarCarrito(!mostrarCarrito)}>
            🛒 Carrito ({carrito.length})
          </button>
        </header>

        {/* Vista de productos o carrito */}
        {!mostrarCarrito ? (
          <div className="productos-grid">
            {productos.map((producto) => (
              <div key={producto.id} className="producto-card">
                <h4>{producto.nombre}</h4>
                <p>Precio: ${producto.precio}</p>
                <p>Stock: {producto.stock}</p>
                <button onClick={() => agregarAlCarrito(producto)}>Agregar al carrito</button>
              </div>
            ))}
          </div>
        ) : (
          <div className="carrito">
            <h3>Carrito de Compras</h3>
            {carrito.length === 0 ? (
              <p>No hay productos en el carrito</p>
            ) : (
              <div>
                {carrito.map((p) => (
                  <div key={p.id} className="carrito-item">
                    <span>{p.nombre} - ${p.precio}</span>
                    <input
                      type="number"
                      value={p.cantidad}
                      min="1"
                      onChange={(e) => actualizarCantidad(p.id, parseInt(e.target.value))}
                    />
                    <button onClick={() => eliminarProducto(p.id)}>Eliminar</button>
                  </div>
                ))}
                <h4>Total: ${total.toFixed(2)}</h4>
                <h4>Método de pago:</h4>
                <select>
                  <option>Tarjeta</option>
                  <option>PayPal</option>
                  <option>Transferencia</option>
                </select>
                <button className="confirm-btn">Confirmar compra</button>
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
}

export default ClienteDashboard;
